class Solution {
public:
    // Find first occurrence of key
    int findFirst(const vector<int>& arr, int key) {
        int left = 0, right = arr.size() - 1;
        int first = -1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (arr[mid] < key) {
                left = mid + 1;
            } else if (arr[mid] > key) {
                right = mid - 1;
            } else {
                first = mid;
                right = mid - 1;  // Search on the left side
            }
        }
        return first;
    }

    // Find last occurrence of key
    int findLast(const vector<int>& arr, int key) {
        int left = 0, right = arr.size() - 1;
        int last = -1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (arr[mid] < key) {
                left = mid + 1;
            } else if (arr[mid] > key) {
                right = mid - 1;
            } else {
                last = mid;
                left = mid + 1;  // Search on the right side
            }
        }
        return last;
    }

    // Solve function that returns the result pair
    vector<int> searchRange(const vector<int>& arr, int key) {
        int first = findFirst(arr, key);
        int last = findLast(arr, key);
        return {first, last};
    }
};

