class Solution {
    findFirst(arr, key) {
        let left = 0, right = arr.length - 1;
        let first = -1;

        while (left <= right) {
            let mid = Math.floor(left + (right - left) / 2);

            if (arr[mid] < key) {
                left = mid + 1;
            } else if (arr[mid] > key) {
                right = mid - 1;
            } else {
                first = mid;
                right = mid - 1;
            }
        }

        return first;
    }

    findLast(arr, key) {
        let left = 0, right = arr.length - 1;
        let last = -1;

        while (left <= right) {
            let mid = Math.floor(left + (right - left) / 2);

            if (arr[mid] < key) {
                left = mid + 1;
            } else if (arr[mid] > key) {
                right = mid - 1;
            } else {
                last = mid;
                left = mid + 1;
            }
        }

        return last;
    }

    searchRange(arr, key) {
        const first = this.findFirst(arr, key);
        const last = this.findLast(arr, key);
        return [first, last];
